def chocolate_distribution(arr, M):
    N = len(arr)

    if M == 0 or N == 0:
        return 0

    if M > N:
        return -1  # Not enough packets for M students

    arr.sort()

    min_diff = float('inf')

    for i in range(N - M + 1):
        current_diff = arr[i + M - 1] - arr[i]
        min_diff = min(min_diff, current_diff)

    return min_diff
